// AUTO-GENERATED by workflow — art. Do not hand-edit; re-run integrate.mjs.
// ENHANCED EDITION (art_v2): generated UNDEAD enemies (+icons).
// Creepy-cool anime undead — bone sheen, ghostly glow, ember/void eyes, tattered
// cloth. Top-left light source, 3–4 tonal steps per material, rim light + soft
// ground shadow, glowing eyes with catch-lights, kira sparkles and pulsing auras.
// Names / dims / frames / anchors / imports are kept byte-compatible contracts.
import { defineSprite, defineAnim, Painter } from '../../engine/sprites.js';
import { P, lighten, darken, mix, withAlpha, tint } from '../../engine/palette.js';
import { defineIcon, panel, sym } from '../icons.js';
import { drawSlime, drawBat, drawWisp, drawBrute, drawHunter } from '../core.js';

// Shared skeleton/undead pixel helpers. Local to this pack, reused across variants.
function ud_skull(p, cx, ty, bone, boneD, eye = P.emberL) {
  const boneL = lighten(bone, 0.22);
  // cranium — shadow base, body, top-left sheen
  p.ellipse(cx, ty + 2, 3, 3, boneD);
  p.ellipse(cx, ty + 2, 2.4, 2.4, bone);
  p.ellipse(cx - 1, ty + 1, 1.3, 1.3, boneL);
  p.px(cx - 1, ty, P.rim);
  // jaw
  p.rect(cx - 2, ty + 4, 4, 2, boneD);
  p.rect(cx - 2, ty + 4, 4, 1, bone);
  p.px(cx - 1, ty + 5, boneD); p.px(cx, ty + 5, boneD); p.px(cx + 1, ty + 5, boneD);
  // eye sockets (glowing) — soft glow, then bright core + white catch-light
  p.rect(cx - 2, ty + 2, 1, 2, P.ink);
  p.rect(cx + 1, ty + 2, 1, 2, P.ink);
  p.glow(cx - 1.5, ty + 2.5, 2, eye, 0.5, 3);
  p.glow(cx + 1.5, ty + 2.5, 2, eye, 0.5, 3);
  p.px(cx - 2, ty + 2, eye); p.px(cx + 1, ty + 2, eye);
  p.px(cx - 2, ty + 2, lighten(eye, 0.4)); p.px(cx + 1, ty + 2, lighten(eye, 0.4));
  // nasal cavity
  p.px(cx, ty + 3, P.ink);
}

function ud_ribs(p, cx, ty, by, bone, boneD) {
  const boneL = lighten(bone, 0.2);
  // spine
  p.vline(ty, by, cx, boneD);
  p.vline(ty, by - 1, cx, bone);
  // rib pairs with a tiny top-left sheen on the upper ribs
  for (let y = ty; y < by; y += 2) {
    p.hline(cx - 3, cx - 1, y, bone);
    p.hline(cx + 1, cx + 3, y, bone);
    p.px(cx - 3, y, boneD); p.px(cx + 3, y, boneD);
    if (y < ty + 3) { p.px(cx - 2, y, boneL); }
  }
}

// soft phantom glow puddle under a floating spirit (per-frame phase optional)
function ud_spectralWash(p, cx, cy, r, col, phase = 0) {
  p.glow(cx, cy, r, col, 0.28, 4);
  p.aura(cx, cy, r + 1, col, phase, 2);
}

// ---------------------------------------------------------------------------
// g_skeleton — bony footsoldier with a rusted cleaver. 16x18, feet anchored.
// ---------------------------------------------------------------------------
defineAnim('g_skeleton', 16, 18, 4, (p, f) => {
  const bone = P.bone, boneD = darken(P.bone, 0.32), boneL = lighten(P.bone, 0.22);
  const bob = (f === 1 || f === 3) ? 1 : 0;
  const step = f === 1 ? 1 : f === 3 ? -1 : 0;
  const oy = -bob;
  // ground contact shadow
  p.softShadow(8, 17, 5, 1.6, 0.34);
  // leg bones
  p.vline(13 + oy, 17 + oy, 6, boneD); p.vline(13 + oy, 17 + oy, 9, boneD);
  p.vline(13 + oy, 16 + oy, 6, bone); p.vline(13 + oy, 16 + oy, 9, bone);
  if (step > 0) p.px(6, 17 + oy, boneD);
  if (step < 0) p.px(9, 17 + oy, boneD);
  // pelvis
  p.rect(5, 12 + oy, 6, 2, boneD);
  p.hline(5, 10, 12 + oy, bone);
  // rib cage
  ud_ribs(p, 8, 7 + oy, 12 + oy, bone, boneD);
  // collar / shoulders
  p.hline(4, 11, 7 + oy, bone);
  p.px(5, 7 + oy, boneL);
  // arms (bone)
  p.vline(7 + oy, 11 + oy, 3, boneD);
  p.vline(7 + oy, 11 + oy, 12, boneD);
  p.px(3, 8 + oy, bone);
  // tattered shoulder rag for silhouette
  p.px(4, 8 + oy, mix(P.greenD, P.ink, 0.3));
  p.px(3, 9 + oy, mix(P.greenD, P.ink, 0.4));
  // skull
  ud_skull(p, 8, 1 + oy, bone, boneD, P.emberL);
  // rusty cleaver in right hand — wood haft, steel blade with ember glint
  p.vline(9 + oy, 13 + oy, 12, P.woodD);
  p.px(12, 11 + oy, P.woodL);
  p.rect(11, 8 + oy, 3, 4, P.steelD);
  p.rect(11, 8 + oy, 3, 1, P.steel);
  p.px(11, 8 + oy, P.steelL);
  p.px(13, 9 + oy, P.iron);
  p.px(13, 8 + oy, P.glint); // blade glint
  // ember motes near the eyes on the off-beat for spook
  if (f === 2) p.px(5, 1 + oy, withAlpha(P.emberL, 0.7));
  p.rimLight(P.rim, 0.5);
  p.outline(P.ink);
}, { anchor: [8, 17], fps: 6 });

// ---------------------------------------------------------------------------
// g_bonearcher — skeletal archer that looses bone arrows. 16x18.
// ---------------------------------------------------------------------------
defineAnim('g_bonearcher', 16, 18, 4, (p, f) => {
  const bone = mix(P.bone, P.greenD, 0.18), boneD = darken(bone, 0.34);
  const hood = mix(P.greenD, P.ink, 0.25), hoodL = mix(P.greenD, P.toxic, 0.3);
  const draw = (f === 2); // mid-frame: bowstring drawn
  const oy = (f === 1 || f === 3) ? -1 : 0;
  p.softShadow(8, 17, 5, 1.6, 0.32);
  // legs
  p.vline(13 + oy, 17 + oy, 6, boneD); p.vline(13 + oy, 17 + oy, 9, boneD);
  p.vline(13 + oy, 16 + oy, 6, bone); p.vline(13 + oy, 16 + oy, 9, bone);
  p.rect(5, 12 + oy, 6, 2, boneD);
  ud_ribs(p, 8, 7 + oy, 12 + oy, bone, boneD);
  // tattered hood remnant with a toxic-green inner sheen
  p.ellipse(8, 3 + oy, 3.4, 2.8, hood);
  p.ellipse(8, 3 + oy, 2.4, 2, mix(hood, P.toxic, 0.15));
  p.px(6, 1 + oy, hoodL);
  // dangling cloth shreds
  p.px(5, 6 + oy, hood); p.px(11, 6 + oy, hood); p.px(5, 7 + oy, mix(hood, P.ink, 0.4));
  ud_skull(p, 8, 1 + oy, bone, boneD, P.toxic);
  // bow held forward (left)
  p.line(2, 4 + oy, 2, 13 + oy, P.woodL);
  p.line(2, 4 + oy, 3, 3 + oy, P.woodD);
  p.line(2, 13 + oy, 3, 14 + oy, P.woodD);
  p.px(2, 8 + oy, lighten(P.woodL, 0.3));
  // bowstring + nocked arrow
  if (draw) {
    p.line(2, 4 + oy, 6, 8 + oy, P.gray3);
    p.line(2, 13 + oy, 6, 8 + oy, P.gray3);
    p.hline(2, 6, 8 + oy, P.bone); p.px(2, 8 + oy, P.toxic);
    p.glow(2, 8 + oy, 2, P.toxic, 0.5, 3); // soul-arrow charge
    p.px(2, 8 + oy, P.glint);
  } else {
    p.line(2, 4 + oy, 3, 8 + oy, P.gray3);
    p.line(2, 13 + oy, 3, 8 + oy, P.gray3);
  }
  // drawing arm
  p.vline(7 + oy, 9 + oy, 11, boneD);
  p.px(11, 8 + oy, bone);
  p.rimLight(P.rimCool, 0.45);
  p.outline(P.ink);
}, { anchor: [8, 17], fps: 5 });

// projectile: bone arrow used by g_bonearcher
defineSprite('g_bonearrow', 8, 8, (p) => {
  // toxic soul trail
  p.glow(1, 4, 2, P.toxic, 0.4, 3);
  p.hline(0, 6, 4, P.bone);
  p.hline(0, 5, 3, darken(P.bone, 0.2));
  p.px(1, 4, lighten(P.bone, 0.3));
  p.px(6, 4, P.gray3); p.px(7, 4, P.steelL); // tip
  p.px(7, 4, P.glint);
  p.px(0, 3, P.toxic); p.px(0, 5, P.toxic);  // fletch
  p.px(0, 4, lighten(P.toxic, 0.3));
}, { anchor: [4, 4] });

// ---------------------------------------------------------------------------
// g_ghoul — hunched rotting carrion-eater. Reuses drawHunter base in sickly
// flesh tones, then adds gore, claw fingers and a dripping maw.
// ---------------------------------------------------------------------------
defineAnim('g_ghoul', 16, 18, 4, (p, f) => {
  const flesh = mix(P.greenD, P.skinD, 0.45);
  const fleshD = darken(flesh, 0.3);
  const fleshL = lighten(flesh, 0.22);
  p.softShadow(8, 17, 5, 1.6, 0.32);
  drawHunter(p, f, { cloak: flesh, cloakD: fleshD, cloakL: fleshL, trim: P.blood, eye: P.poison, skin: flesh });
  const oy = (f === 1 || f === 3) ? -1 : 0;
  // poison glow behind the sunken eyes
  p.glow(6, 6 + oy, 1.6, P.poison, 0.45, 3);
  p.glow(9, 6 + oy, 1.6, P.poison, 0.45, 3);
  p.px(6, 6 + oy, P.toxic); p.px(9, 6 + oy, P.toxic);
  // sunken cheeks / rotten patches over the face shadow
  p.px(6, 9 + oy, P.blood); p.px(9, 8 + oy, P.blood);
  p.px(10, 10 + oy, fleshD);
  p.px(5, 8 + oy, mix(P.poison, fleshD, 0.5)); // sickly highlight
  // exposed claw fingers
  p.px(2, 14 + oy, P.bone); p.px(2, 15 + oy, P.bone);
  p.px(13, 14 + oy, P.bone); p.px(13, 15 + oy, P.bone);
  p.px(2, 13 + oy, lighten(P.bone, 0.2));
  // dripping maw with a wet glint
  p.rect(6, 10 + oy, 4, 1, P.blood);
  p.px(7, 11 + oy, P.red);
  p.px(8, 11 + oy, withAlpha(P.redL, 0.7));
  p.rimLight(mix(P.poison, P.rim, 0.4), 0.4);
  p.outline(P.ink);
}, { anchor: [8, 17], fps: 6 });

// ---------------------------------------------------------------------------
// g_necromancer — dark-robed undead caster. drawHunter variant (void robe),
// hurls shadow bolts. Adds a bone staff topped with a green soul-flame.
// ---------------------------------------------------------------------------
defineAnim('g_necromancer', 16, 18, 4, (p, f) => {
  p.softShadow(8, 17, 5, 1.6, 0.34);
  drawHunter(p, f, { cloak: P.purpleD, cloakD: P.void, cloakL: P.purple, trim: P.toxic, eye: P.toxic, skin: P.bone });
  const oy = (f === 1 || f === 3) ? -1 : 0;
  const phase = f / 4;
  // astral aura on the cast frames for caster drama
  if (f === 1 || f === 2) p.aura(8, 9 + oy, 6, P.astral, phase, 2);
  // skeletal staff in right hand with a soul flame
  p.line(12, 14 + oy, 15, 5 + oy, P.bone);
  p.px(13, 11 + oy, lighten(P.bone, 0.25));
  // soul flame — soft glow then bright tiered flame + white core
  p.glow(15, 4 + oy, 3, P.toxic, 0.5, 4);
  p.px(15, 4 + oy, P.toxic);
  p.ellipse(15, 4 + oy, 1.6, 2.2, P.greenD);
  p.ellipse(15, 3 + oy, 1, 1.4, P.toxic);
  p.px(15, 2 + oy, P.white);
  p.px(15, 1 + oy, withAlpha(P.toxic, 0.6));
  // glowing eyes pop
  p.px(6, 6 + oy, P.toxic); p.px(9, 6 + oy, P.toxic);
  // bone trim on the hood
  p.px(5, 4 + oy, P.bone); p.px(10, 4 + oy, P.bone);
  // sakura-cool rune glint on the chest
  p.px(8, 9 + oy, withAlpha(P.astralL, 0.8));
  p.rimLight(P.astralL, 0.4);
  p.outline(P.ink);
}, { anchor: [8, 17], fps: 6 });

